# 교재 설명 읽고 짠 코드

n, m = 4, 6
array = [19,15,10,17]

start = 0
end = max(array)

def remainder(array, mid):
    result = []
    for i in array:
        if i > mid:
            result.append(i - mid)
    return sum(result)

def bi_search(array, m, start, end):
    while start <= end:
        mid = (start + end) // 2
        if remainder(array, mid) == m:
            return mid
        elif remainder(array, mid) > m:
            start = mid + 1
        else:
            end = mid - 1

print(bi_search(array, m, start, end))
